import { useState } from "react";
import { CountdownCircleTimer } from "react-countdown-circle-timer";
import MoreTimeIcon from "@mui/icons-material/MoreTime";
import PlayArrowIcon from "@mui/icons-material/PlayArrow";
import PauseIcon from "@mui/icons-material/Pause";
import RestartAltIcon from "@mui/icons-material/RestartAlt";
import SimpleDialog from "@mui/material/Dialog";
import Button from "@mui/material/Button";
import DialogContent from "@mui/material/DialogContent";

const Timer = ({ elapsedTimeHandler }) => {
  const [timer, setTimer] = useState("");
  const [isTimeSelectionOpen, setTimeSelectionOpen] = useState(false);
  const [isTimeRunning, setTimeRunning] = useState(false);
  const [timerKey, setTimerKey] = useState(0);

  const handleTimeSelection = (e) => {
    setTimerKey(timerKey + 1);
    elapsedTimeHandler(0);
    setTimer(e.target.value);
    setTimeSelectionOpen(false);
  };

  const convertTimeToSeconds = (timer) => {
    var seconds = timer.split(":")[1];
    var minutes = timer.split(":")[0];
    if (timer !== "") return Number(seconds) + Number(minutes * 60);
    return 0;
  };

  return (
    <div className="timer">
      <div className="timer__circle">
        <CountdownCircleTimer
          isPlaying={isTimeRunning}
          key={timerKey}
          size={70}
          strokeWidth={5}
          trailColor="#8e8e8e"
          colors={["#fff"]}
          className="timer__circle"
          duration={convertTimeToSeconds(timer)}
          rotation="counterclockwise"
          initialRemainingTime={convertTimeToSeconds(timer)}
        >
          {({ remainingTime, elapsedTime }) => {
            const minutes = Math.floor(remainingTime / 60);
            const seconds = remainingTime % 60;

            elapsedTimeHandler(elapsedTime);

            if (!timer || isTimeSelectionOpen)
              return (
                <>
                  <MoreTimeIcon onClick={() => setTimeSelectionOpen(true)} />
                  <SimpleDialog
                    open={isTimeSelectionOpen}
                    onClose={() => setTimeSelectionOpen(false)}
                  >
                    <DialogContent>
                      <Button value="10:00" onClick={handleTimeSelection}>
                        10:00
                      </Button>
                      <Button value="20:00" onClick={handleTimeSelection}>
                        20:00
                      </Button>
                      <Button value="30:00" onClick={handleTimeSelection}>
                        30:00
                      </Button>
                      <Button value="40:00" onClick={handleTimeSelection}>
                        40:00
                      </Button>
                      <Button value="50:00" onClick={handleTimeSelection}>
                        50:00
                      </Button>
                      <Button value="60:00" onClick={handleTimeSelection}>
                        60:00
                      </Button>
                    </DialogContent>
                  </SimpleDialog>
                </>
              );

            return (
              <div
                onClick={() => {
                  if (!isTimeRunning) setTimeSelectionOpen(true);
                }}
              >
                {`${minutes}:${seconds < 10 ? "0" + seconds : seconds}`}
              </div>
            );
          }}
        </CountdownCircleTimer>
      </div>
      <div className="timer__button">
        {isTimeRunning ? (
          <PauseIcon
            onClick={() => {
              if (timer) setTimeRunning(false);
            }}
          />
        ) : (
          <PlayArrowIcon
            onClick={() => {
              if (timer) setTimeRunning(true);
            }}
          />
        )}
        <RestartAltIcon
          onClick={() => {
            setTimeRunning(false);
            elapsedTimeHandler(0);
            setTimerKey(timerKey + 1);
            setTimer("");
          }}
        />
      </div>
    </div>
  );
};

export default Timer;
