import { React, useState, useEffect } from "react";
import { v4 as uuid } from "uuid";
import moment from "moment";

import "../css/Note.css";
import Note from "./Note";
import CreateNote from "./CreateNote";

const Notes = () => {
  const savedNotes = localStorage.getItem("Notes")
    ? JSON.parse(localStorage.getItem("Notes"))
    : [];

  //states
  const [notes, setNotes] = useState(savedNotes);
  const [title, setTitle] = useState("");
  const [text, setText] = useState("");
  const [elapsedTime, setElapsedTime] = useState(0);
  const [categorySelected, setCategorySelected] = useState([]);

  const formatDate = moment().format("ll");

  //saving data to local storage
  useEffect(() => {
    localStorage.setItem("Notes", JSON.stringify(notes));
  }, [notes]);

  const saveHandler = () => {
    const elapsedTimeFormated = moment.utc(elapsedTime * 1000).format("mm:ss");
    setNotes((prevState) => [
      {
        id: uuid(),
        text,
        date: formatDate,
        title,
        elapsedTime: elapsedTimeFormated,
        categorySelected,
      },
      ...prevState,
    ]);
    //clear the textarea
    setText("");
    setTitle("");
    setElapsedTime(0);
    // setCategorySelected([]);
  };

  //delete note function
  const deleteNote = (id) => {
    const filteredNotes = notes.filter((note) => note.id !== id);
    setNotes(filteredNotes);
  };

  return (
    <div>
      <div className="create-note">
        <CreateNote
          titleHandler={(e) => setTitle(e.target.value)}
          textHandler={setText}
          elapsedTimeHandler={setElapsedTime}
          saveHandler={saveHandler}
          categorySelectedHandler={setCategorySelected}
          text={text}
          title={title}
          formatDate={formatDate}
          categorySelected={categorySelected}
        />
      </div>
      <hr />
      <div className="notes">
        {notes.map((note) => (
          <Note
            key={note.id}
            id={note.id}
            text={note.text}
            title={note.title}
            date={note.date}
            elapsedTime={note.elapsedTime}
            category={note.categorySelected}
            deleteNote={deleteNote}
          />
        ))}
      </div>
    </div>
  );
};

export default Notes;
