import DeleteForeverOutlinedIcon from "@mui/icons-material/DeleteForeverOutlined";
import Chip from "@mui/material/Chip";

const Note = ({ id, text, date, title, elapsedTime, category, deleteNote }) => {
  return (
    <div className="note note__box">
      {title && <div style={{ fontWeight: "bold" }}>{title}</div>}
      <div style={{ fontStyle: "italic" }}>{date}</div>
      <div className="note__body">
        {/* <div>{text}</div> */}
        <div
          style={{
            display: "flex",
            justifyContent: "center",
            border: "1px solid #fff",
            borderRadius: "5px",
            width: "60px",
            margin: "auto",
            textAlign: "center",
          }}
        >
          {elapsedTime}
        </div>
      </div>
      <div className="note--space-between">
        {category && (
          <div>
            {category.map((value) => (
              <Chip
                key={value}
                label={value}
                sx={{
                  color: "#fff",
                  backgroundColor: "#AED8BA",
                  height: "24px",
                  fontSize: "9px",
                  marginLeft: "2px",
                }}
              />
            ))}
          </div>
        )}
        <DeleteForeverOutlinedIcon
          className="note__delete"
          onClick={() => deleteNote(id)}
          aria-hidden="true"
        ></DeleteForeverOutlinedIcon>
      </div>
    </div>
  );
};

export default Note;
