import { useState } from "react";
import Select from "@mui/material/Select";
import Box from "@mui/material/Box";
import Chip from "@mui/material/Chip";
import OutlinedInput from "@mui/material/OutlinedInput";
import MenuItem from "@mui/material/MenuItem";
import InputLabel from "@mui/material/InputLabel";
import FormControl from "@mui/material/FormControl";

import ReactQuill from "react-quill";
import "../css/Editor.css";
import "react-quill/dist/quill.snow.css";

import Timer from "./Timer";

const CreateNote = ({
  textHandler,
  saveHandler,
  titleHandler,
  elapsedTimeHandler,
  categorySelectedHandler,
  text,
  title,
  formatDate,
  categorySelected,
}) => {
  const [isNoteOpen, setNoteOpen] = useState(false);

  const categories = [
    "ReactJS",
    "Typescript",
    "CSS",
    "NextJS",
    "Database",
    "UX Design",
  ];

  const handleCategorySelected = (e) => {
    const {
      target: { value },
    } = e;
    categorySelectedHandler(
      typeof value === "string" ? value.split(",") : value
    );
  };

  return (
    <div
      className="note"
      style={
        {
          // background: "rgba(255, 255, 255, 0)",
        }
      }
    >
      {isNoteOpen && (
        <div className="note__params">
          <span className="note--center">{formatDate}</span>
          <input
            value={title}
            onChange={titleHandler}
            className={`title ${title && "title--value"}`}
            placeholder="Title"
          />
          <div className="note__timer-category">
            <FormControl sx={{ display: "flex" }}>
              <InputLabel
                id="multiple-chip-label"
                sx={{
                  fontFamily: "Montserrat",
                  color: "#96a3ad !important",
                  visibility:
                    categorySelected.length > 0 ? "hidden" : "visible", // TODO: fix border top to fit label
                }}
              >
                Category
              </InputLabel>
              <Select
                disabled={false}
                labelId="multiple-chip-label"
                className="category"
                multiple
                value={categorySelected}
                input={<OutlinedInput id="select-multiple-chip" label="Chip" />}
                onChange={handleCategorySelected}
                sx={{
                  ".MuiSvgIcon-root ": {
                    fill: "white !important",
                  },
                }}
                renderValue={(selected) => (
                  <Box
                    sx={{
                      display: "flex",
                      flexWrap: "wrap",
                      gap: 0.5,
                    }}
                  >
                    {selected.map((value) => (
                      <Chip
                        key={value}
                        label={value}
                        sx={{
                          color: "#fff",
                          backgroundColor: "#AED8BA",
                        }}
                      />
                    ))}
                  </Box>
                )}
              >
                {categories.map((category) => (
                  <MenuItem
                    key={category}
                    value={category}
                    style={{
                      fontWeight:
                        categorySelected.indexOf(category) === -1 ? 400 : 500,
                      color: "#96a3ad",
                    }}
                  >
                    {category}
                  </MenuItem>
                ))}
              </Select>
            </FormControl>
            <Timer elapsedTimeHandler={elapsedTimeHandler} />
          </div>
          <hr />
        </div>
      )}
      <div
        style={!isNoteOpen ? { cursor: "text" } : {}}
        onClick={() => {
          setNoteOpen(true);
        }}
        // onChange={textHandler}
        className={`editor ${
          isNoteOpen ? "editor-anmiation--open" : "editor-anmiation--close"
        }`}
      >
        {isNoteOpen ? (
          <ReactQuill
            value={text}
            onChange={textHandler}
            style={{ border: "none" }}
            placeholder="Insert note ..."
          />
        ) : (
          "Start my watch ...."
        )}
      </div>
      <div className="note--space-between">
        <button
          className="note__button"
          onClick={() => {
            setNoteOpen(false);
          }}
        >
          Close
        </button>
        <button
          className="note__button"
          onClick={saveHandler}
          // disabled={text === "" ? true : false}
        >
          Save
        </button>
      </div>
    </div>
  );
};

export default CreateNote;
